override fun close() {
    if (closed) return
    closed = true
    try {
        writeHeaderIfNeeded()
        flushChunk()
        output.flush()
        patchTotalPlaintextSizeIfPossible()
    } catch (e: Exception) {
        Timber.e(e, "ChunkedGcmOutputStream: close failed")   // swallowed
    } finally {
        output.close()
    }
}
```
